const saludos = ['hola','hi','hello','buenas','buenos','buen','inicio','menu','start','0','holi','qué hay','que hay'];
let msg;
if (saludos.some(s => text.startsWith(s)) || text === '') {
  msg = MENU;
} else if (text === '1' || text.includes('plan') || text.includes('precio') || text.includes('membres')) {
