} else if (text === '4' || text.includes('hablar') || text.includes('equipo') || text.includes('persona') || text.includes('asesor')) {
  msg = EQUIPO;
} else if (text.includes('inscrib') || text.includes('registro') || text.includes('comprar') || text.includes('quiero')) {
